prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?gwId ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1f1b01e0a85340689b6df314b32bb4b6" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?gw tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?gw a bboExt:ParallelGateway .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bbo:id ?gwId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?gwId ?modelName ?idType WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:normalizedId ?normId .
  OPTIONAL { ?model tai:originalId ?origId . }
  BIND(STR(?normId) AS ?normIdStr)
  BIND(STR(?origId) AS ?origIdStr)
  BIND("normalized" AS ?idType)
  FILTER(?normIdStr = "1f1b01e0a85340689b6df314b32bb4b6" || ?origIdStr = "1f1b01e0a85340689b6df314b32bb4b6")

  OPTIONAL { ?model bbo:name ?modelName . }
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?gw tai:belongsTo ?choreo .
  ?gw a bboExt:ParallelGateway .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bbo:id ?gwId . }
}
LIMIT 25
